  async function submitAssessment() { const answer = $('assessmentAnswer').value.trim(); if (answer.split(/\s+/).length < 20) return toast('A avaliação precisa de uma resposta mais completa.'); const template = assessmentTemplates[[30, 60, 90, 120, 150, 180].indexOf(assessmentMilestone)]; $('assessmentFeedback').innerHTML = '<div class="grace-mini">G</div><p>Avaliando...</p>'; const ai = await GraceAI.ask('assessment', { milestone: assessmentMilestone, prompt: template.prompt, answer, profile: studentProfile(), memory: memorySummary(), level: appLevel() }); let score = ai?.score != null ? Number(ai.score) : Math.min(88, 45 + answer.split(/\s+/).length); const feedback = ai?.feedback || 'Boa produção. Continue trabalhando clareza, estrutura e vocabulário específico.'; if (ai) applyAiMemory(ai); state.assessments[assessmentMilestone] = { date: localDateKey(), score, feedback, answer }; state.xp += 150; state.skills.writing = clamp(state.skills.writing + 4, 0, 100); recordActivity(20); saveState(); $('assessmentFeedback').innerHTML = `<div class="grace-mini">G</div><p><b>${score}%</b><br>${escapeHtml(feedback)}</p>`; renderAssessments(); }

  function renderPractice() {
    $('practiceDate').value ||= localDateKey(); const weekStart = currentWeekStart(); const sessions = state.practiceSessions.filter(s => new Date(`${s.date}T12:00:00`) >= weekStart); $('practiceWeekStatus').textContent = `${sessions.length}/2 conversas`;
    $('practiceHistory').innerHTML = state.practiceSessions.slice(-6).reverse().map(s => `<div class="history-item"><b>${escapeHtml(s.partner || 'Prática')}</b><small>${escapeHtml(s.date)} • ${s.minutes} minutos</small><p>${escapeHtml(s.notes || '')}</p></div>`).join('') || '<p>Nenhuma sessão registrada.</p>';
    const lesson = getLesson(); $('weeklyRecordingTitle').textContent = `Semana ${Math.ceil(state.day / 7)} • ${lesson.shortTitle}`; $('weeklyRecordingPrompt').textContent = lesson.speakingMission;
  }
  function savePractice() { const session = { partner: $('practicePartner').value.trim() || 'Parceiro de conversação', date: $('practiceDate').value || localDateKey(), minutes: Number($('practiceMinutes').value || 30), notes: $('practiceNotes').value.trim() }; state.practiceSessions.push(session); state.xp += 40; recordActivity(session.minutes); saveState(); $('practicePartner').value = ''; $('practiceNotes').value = ''; toast('Prática real registrada. +40 XP'); }
  async function startRecording() { if (!navigator.mediaDevices?.getUserMedia || !window.MediaRecorder) return toast('Seu navegador não oferece gravação. Use Chrome ou Edge.'); try { const stream = await navigator.mediaDevices.getUserMedia({ audio: true }); mediaChunks = []; mediaRecorder = new MediaRecorder(stream); mediaRecorder.ondataavailable = e => e.data.size && mediaChunks.push(e.data); mediaRecorder.onstop = () => { const blob = new Blob(mediaChunks, { type: mediaRecorder.mimeType || 'audio/webm' }); if (currentRecordingUrl) URL.revokeObjectURL(currentRecordingUrl); currentRecordingUrl = URL.createObjectURL(blob); $('recordingPlayback').src = currentRecordingUrl; $('recordingPlayback').classList.remove('hidden'); $('downloadRecording').href = currentRecordingUrl; $('downloadRecording').classList.remove('hidden'); $('recordingFeedback').textContent = 'Escute agora. Depois grave uma segunda versão corrigindo pausas e clareza.'; stream.getTracks().forEach(t => t.stop()); state.xp += 25; state.skills.speaking = clamp(state.skills.speaking + 2, 0, 100); saveState(); }; mediaRecorder.start(); $('startRecording').classList.add('recording'); $('startRecording').disabled = true; $('stopRecording').disabled = false; $('recordingFeedback').textContent = 'Gravando... fale com calma e não leia palavra por palavra.'; } catch { toast('Permissão de microfone não concedida.'); } }
  function stopRecording() { if (mediaRecorder?.state === 'recording') mediaRecorder.stop(); $('startRecording').classList.remove('recording'); $('startRecording').disabled = false; $('stopRecording').disabled = true; }

  function renderReports() {
    $('reportMinutes').textContent = state.studyMinutes; $('reportConversations').textContent = state.conversations + state.practiceSessions.length; $('reportAssessments').textContent = Object.keys(state.assessments).length; const scores = state.pronunciationScores.map(x => x.score).concat(Object.values(state.assessments).map(x => Number(x.score))); $('reportAccuracy').textContent = `${scores.length ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : 0}%`;
    const dates = Array.from({ length: 14 }, (_, i) => { const d = new Date(); d.setDate(d.getDate() - (13 - i)); return d; }); const max = Math.max(1, ...dates.map(d => state.activity[localDateKey(d)] || 0)); $('activityChart').innerHTML = dates.map(d => { const value = state.activity[localDateKey(d)] || 0; return `<div class="activity-bar" title="${value} minutos" style="height:${Math.max(5, value / max * 100)}%"><span>${d.getDate()}</span></div>`; }).join('');
    const errors = Object.values(state.errors).sort((a, b) => b.count - a.count); $('errorMemoryList').innerHTML = errors.slice(0, 10).map(e => `<div class="memory-item"><b>${escapeHtml(e.label)} • ${e.count}x</b><small>${escapeHtml(e.correction || e.example || 'Revisar')}</small></div>`).join('') || '<p>Nenhum padrão de erro registrado.</p>'; $('reviewWordList').innerHTML = Object.values(state.reviewWords).sort((a, b) => b.count - a.count).slice(0, 20).map(w => `<span class="tag">${escapeHtml(w.word)}</span>`).join('') || '<p>Nenhuma palavra marcada.</p>'; $('aiWeeklyReport').innerHTML = state.aiReport ? `<p>${escapeHtml(state.aiReport)}</p>` : '<p>Conclua atividades para receber uma análise semanal.</p>';
    state.dailySteps.review = errors.length > 0 && Object.values(state.reviewWords).length > 0; renderDashboard();
  }
  async function generateAiReport() { $('aiWeeklyReport').innerHTML = '<p>Grace está analisando sua semana...</p>'; const ai = await GraceAI.ask('weekly_report', { profile: studentProfile(), state: reportSummary(), memory: memorySummary() }); state.aiReport = ai?.feedback || localWeeklyReport(); saveState(); $('aiWeeklyReport').innerHTML = `<p>${escapeHtml(state.aiReport)}</p>`; }
  function localWeeklyReport() { const errors = Object.values(state.errors).sort((a, b) => b.count - a.count); return `Você estudou aproximadamente ${state.studyMinutes} minutos no total. Sua prioridade agora é ${errors[0]?.label || 'manter a constância'}, com foco especial em fala e escuta. Faça duas conversas reais nesta semana.`; }

  function renderRoadmap() { const progress = Math.round(state.completed.length / 180 * 100); $('roadmapProgress').textContent = `${progress}% concluído`; $('phaseGrid').innerHTML = phases.map((phase, i) => { const start = i * 30 + 1, end = start + 29, done = state.completed.filter(d => d >= start && d <= end).length; return `<article class="phase-card"><div class="eyebrow">${phase.range} • ${phase.level}</div><h3>${phase.name}</h3><p>${phase.description}</p><div class="large-progress"><i style="width:${Math.round(done / 30 * 100)}%"></i></div><small>${done}/30 dias</small></article>`; }).join(''); $('dayMap').innerHTML = Array.from({ length: 180 }, (_, i) => `<div class="day-cell ${state.completed.includes(i + 1) ? 'done' : ''} ${state.day === i + 1 ? 'today' : ''}" title="Dia ${i + 1}: ${escapeHtml(lessons[i].shortTitle)}">${i + 1}</div>`).join(''); }
